/**
 * WordPress dependencies.
 */
import { store as editorStore } from "@wordpress/editor";
import { useDispatch, useSelect } from "@wordpress/data";
import { Button } from "@wordpress/components";
import { __ } from "@wordpress/i18n";

/**
 * External dependencies.
 */
import classNames from "classnames";
import type { ComponentProps } from "react";

/**
 * Internal dependencies.
 */
import { DesktopIcon, MobileIcon, TabletIcon } from "../icons";
import useZoomToggle from "../hooks/useZoomToggle";

type DeviceSwitcherButtonProps = ComponentProps<typeof Button> & { active?: boolean };

function DeviceSwitcherButton({
	active = false,
	className,
	...buttonProps
}: DeviceSwitcherButtonProps) {
	const classes = classNames([
		"nfd-editor-chat__header-device-switcher__button",
		className,
		{
			"nfd-editor-chat__header-device-switcher__button--active": active,
		},
	]);

	const props: ComponentProps<typeof Button> = {
		className: classes,
		...buttonProps,
	};

	return <Button {...props} />;
}

export default function DeviceSwitcher() {
	const { resetZoomLevel } = useZoomToggle();
	const { setDeviceType } = useDispatch(editorStore);

	const { deviceType } = useSelect((select) => {
		const { getDeviceType } = select(editorStore);
		return { deviceType: getDeviceType() };
	}, []);

	const handleDevicePreviewChange = (newDeviceType: string) => {
		setDeviceType(newDeviceType);
		resetZoomLevel();
	};

	const choices = [
		{
			value: "Desktop",
			label: __("Desktop", "wp-module-editor-chat"),
			icon: <DesktopIcon />,
		},
		{
			value: "Tablet",
			label: __("Tablet", "wp-module-editor-chat"),
			icon: <TabletIcon />,
		},
		{
			value: "Mobile",
			label: __("Mobile", "wp-module-editor-chat"),
			icon: <MobileIcon />,
		},
	];

	return (
		<div
			className="nfd-editor-chat__header-device-switcher"
			id="nfd-editor-chat__header__device-switcher"
		>
			{choices.map((choice) => (
				<DeviceSwitcherButton
					key={choice.value}
					onClick={() => handleDevicePreviewChange(choice.value)}
					active={choice.value === deviceType}
					label={choice.label}
					showTooltip
				>
					{choice.icon}
				</DeviceSwitcherButton>
			))}
		</div>
	);
}
